#!/bin/bash
# Builds pdfio (michaelrsweet/pdfio) for $TARGET_PLATFORM. Source repo
# isn't a CMake project — we compile its 16 .c files directly into a
# static archive (same approach the previous from-source cmake used).
#
# windows-x86_64 is intentionally absent — see build.sh for the why.
#
# Required env:
#   TARGET_PLATFORM   linux-x86_64 | linux-aarch64 |
#                     macos-arm64 | macos-x86_64 |
#                     android-arm64-v8a | android-x86_64 |
#                     ios-arm64 | ios-x86_64 |
#                     webasm
#   OUTPUT_DIR        where the tarball is written
#
# Version is read from this directory's `version` file.
#
# Output tarball layout (consumed by libs/pdfio.cmake):
#   lib/libpdfio.a (or pdfio.lib on windows native MSVC)
#   include/pdfio.h, include/pdfio-content.h, include/pdfio-private.h
#
# Note on zlib:
# pdfio's stream filter (FlateDecode) requires zlib at compile AND link
# time. This producer fetches zlib HEADERS at compile time (just zlib.h
# + zconf.h — zlib.h is small and stable), but the resulting .a holds
# UNRESOLVED zlib references that the consumer must satisfy at link
# time. yetty's main build already provides `zlibstatic` via the
# FreeType bundle — libs/pdfio.cmake wires it via INTERFACE_LINK_LIBRARIES.
# Same model libcurl/libssh2 use for their TLS backend deps.

set -Eeuo pipefail
trap 'rc=$?; echo "FAILED: rc=$rc line=$LINENO source=${BASH_SOURCE[0]} cmd: $BASH_COMMAND" >&2' ERR

: "${TARGET_PLATFORM:?TARGET_PLATFORM is required}"
: "${OUTPUT_DIR:?OUTPUT_DIR is required}"

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
VERSION_FILE="$SCRIPT_DIR/version"
[ -f "$VERSION_FILE" ] || { echo "missing $VERSION_FILE" >&2; exit 1; }
VERSION="$(tr -d '[:space:]' < "$VERSION_FILE")"
[ -n "$VERSION" ] || { echo "$VERSION_FILE is empty" >&2; exit 1; }

WORK_DIR="${WORK_DIR:-/tmp/yetty-3rdparty-pdfio-$TARGET_PLATFORM}"
CACHE_DIR="${CACHE_DIR:-$HOME/.cache/yetty-3rdparty}"
NCPU="$(nproc 2>/dev/null || sysctl -n hw.ncpu 2>/dev/null || echo 4)"

PDFIO_URL="https://github.com/michaelrsweet/pdfio/archive/refs/tags/v${VERSION}.tar.gz"
PDFIO_TARBALL="$CACHE_DIR/pdfio-${VERSION}.tar.gz"
SRC_DIR="$WORK_DIR/pdfio-${VERSION}"
INSTALL_DIR="$WORK_DIR/install-${TARGET_PLATFORM}"
STAGE="$WORK_DIR/stage-${TARGET_PLATFORM}"
TARBALL="$OUTPUT_DIR/pdfio-${TARGET_PLATFORM}-${VERSION}.tar.gz"

# zlib headers (we don't link, just need the headers to compile pdfio).
# Pinned to a recent stable zlib; bumping is fine — pdfio uses only the
# stable zlib.h API surface.
ZLIB_VERSION=1.3.1
ZLIB_URL="https://github.com/madler/zlib/archive/refs/tags/v${ZLIB_VERSION}.tar.gz"
ZLIB_TARBALL="$CACHE_DIR/zlib-headers-${ZLIB_VERSION}.tar.gz"
ZLIB_DIR="$WORK_DIR/zlib-${ZLIB_VERSION}"

mkdir -p "$WORK_DIR" "$OUTPUT_DIR" "$CACHE_DIR"

#-----------------------------------------------------------------------------
# Fetch
#-----------------------------------------------------------------------------
fetch() {
    local url="$1" cache="$2" descr="$3"
    if [ ! -f "$cache" ]; then
        local part="$cache.part.$$"
        (
            if command -v flock >/dev/null 2>&1; then flock -x 9; fi
            if [ ! -f "$cache" ]; then
                echo "==> downloading $descr"
                curl -fL --retry 8 --retry-delay 5 --retry-all-errors \
                    -o "$part" "$url"
                mv "$part" "$cache"
            fi
        ) 9>"$CACHE_DIR/.pdfio-download.lock"
        rm -f "$part"
    fi
}

fetch "$PDFIO_URL" "$PDFIO_TARBALL" "pdfio ${VERSION}"
fetch "$ZLIB_URL"  "$ZLIB_TARBALL"  "zlib ${ZLIB_VERSION} (headers only)"

if [ ! -d "$SRC_DIR" ]; then
    echo "==> extracting pdfio"
    tar -C "$WORK_DIR" -xzf "$PDFIO_TARBALL"
fi
if [ ! -d "$ZLIB_DIR" ]; then
    echo "==> extracting zlib (headers)"
    tar -C "$WORK_DIR" -xzf "$ZLIB_TARBALL"
fi
# zlib's zconf.h is generated by configure; the source repo ships zconf.h.in
# — fall back to .in if the generated one isn't present (it usually IS).
if [ ! -f "$ZLIB_DIR/zconf.h" ] && [ -f "$ZLIB_DIR/zconf.h.in" ]; then
    cp "$ZLIB_DIR/zconf.h.in" "$ZLIB_DIR/zconf.h"
fi

rm -rf "$INSTALL_DIR" "$STAGE"
mkdir -p "$INSTALL_DIR/lib" "$INSTALL_DIR/include" "$STAGE"

#-----------------------------------------------------------------------------
# Per-platform compiler.
#-----------------------------------------------------------------------------
# gnu99 (not c99) so POSIX feature-test macros expose strdup, ssize_t, etc.
# Mirrors what cmake's `C_STANDARD 99` + EXTENSIONS=ON (the default) emits.
CFLAGS_BASE="-O2 -fPIC -std=gnu99 -DNDEBUG"
CC=cc
AR=ar
CFLAGS_EXTRA=""
EXTRA_SOURCES=()

case "$TARGET_PLATFORM" in
linux-x86_64) CC=gcc ;;
linux-aarch64)
    : "${CROSS_PREFIX:=aarch64-unknown-linux-gnu-}"
    CC="${CROSS_PREFIX}gcc"
    AR="${CROSS_PREFIX}ar"
    ;;
macos-x86_64) CC=clang; CFLAGS_EXTRA="-arch x86_64" ;;
macos-arm64)  CC=clang; CFLAGS_EXTRA="-arch arm64"  ;;
ios-arm64|ios-x86_64)
    unset DEVELOPER_DIR MACOSX_DEPLOYMENT_TARGET SDKROOT NIX_APPLE_SDK_VERSION
    export PATH="/usr/bin:$PATH"
    : "${IOS_MIN:=15.0}"
    case "$TARGET_PLATFORM" in
        ios-arm64)  _IOS_SDK="iphoneos";        _IOS_ARCH="arm64";  _MIN_FLAG="-miphoneos-version-min=${IOS_MIN}" ;;
        ios-x86_64) _IOS_SDK="iphonesimulator"; _IOS_ARCH="x86_64"; _MIN_FLAG="-mios-simulator-version-min=${IOS_MIN}" ;;
    esac
    _IOS_SYSROOT="$(/usr/bin/xcrun --sdk "$_IOS_SDK" --show-sdk-path)"
    [ -d "$_IOS_SYSROOT" ] || { echo "missing iOS SDK: $_IOS_SYSROOT" >&2; exit 1; }
    CC="/usr/bin/clang"
    AR="/usr/bin/ar"
    CFLAGS_EXTRA="-arch $_IOS_ARCH -isysroot $_IOS_SYSROOT $_MIN_FLAG"
    ;;
android-arm64-v8a|android-x86_64)
    : "${ANDROID_NDK_HOME:?ANDROID_NDK_HOME not set — source the .#3rdparty-${TARGET_PLATFORM} shell}"
    : "${ANDROID_API:=26}"
    case "$TARGET_PLATFORM" in
        android-arm64-v8a) _NDK_TRIPLE="aarch64-linux-android" ;;
        android-x86_64)    _NDK_TRIPLE="x86_64-linux-android"  ;;
    esac
    CC="${_NDK_TRIPLE}${ANDROID_API}-clang"
    AR="llvm-ar"
    command -v "$CC" >/dev/null 2>&1 || { echo "error: $CC not on PATH" >&2; exit 1; }
    # NDK API 26 libc doesn't export getrandom (landed in API 28), and
    # the NDK <sys/random.h> declaration is hidden behind
    # `__ANDROID_API__ >= 28`. We can't bump the API just for pdfio
    # without breaking ABI compat with the rest of yetty, so we
    # force-include a tiny shim header that forward-declares getrandom
    # before pdfio's first call site, and ship a syscall wrapper so the
    # symbol is also satisfied at link time. Linker drops this object if
    # libc ever does provide the symbol (won't happen at API 26).
    cat > "$WORK_DIR/pdfio-getrandom-shim.h" <<'SHIM_EOF'
/* yetty 3rdparty shim: pdfio-crypto.c uses getrandom but the NDK
 * <sys/random.h> hides its declaration when __ANDROID_API__ < 28. The
 * symbol is provided by pdfio-getrandom-stub.c via direct syscall. */
#include <sys/types.h>
#ifdef __cplusplus
extern "C"
#endif
ssize_t getrandom(void *buf, size_t buflen, unsigned int flags);
SHIM_EOF
    CFLAGS_EXTRA="-include $WORK_DIR/pdfio-getrandom-shim.h"
    cat > "$WORK_DIR/pdfio-getrandom-stub.c" <<'STUB_EOF'
/* Android API < 28 stub: getrandom() symbol via direct syscall. */
#include <sys/syscall.h>
#include <sys/types.h>
#include <unistd.h>
ssize_t getrandom(void *buf, size_t buflen, unsigned int flags) {
    return syscall(__NR_getrandom, buf, buflen, flags);
}
STUB_EOF
    EXTRA_SOURCES+=("$WORK_DIR/pdfio-getrandom-stub.c")
    ;;
webasm)
    command -v emcc >/dev/null 2>&1 || { echo "error: emcc not found" >&2; exit 1; }
    CC=emcc
    AR=emar
    # Emscripten lacks getrandom() — yetty ships a stub source the original
    # cmake patched in. Bundle the same stub here so the prebuilt .a is
    # self-contained; the consumer doesn't need to provide an extra source.
    cat > "$WORK_DIR/pdfio-getrandom-stub.c" <<'STUB_EOF'
/* Emscripten stub: provide getrandom() shim that pdfio expects. */
#include <stddef.h>
#include <stdlib.h>
#include <sys/types.h>   /* ssize_t */
ssize_t getrandom(void *buf, size_t buflen, unsigned int flags) {
    (void)flags;
    unsigned char *p = (unsigned char *)buf;
    for (size_t i = 0; i < buflen; i++) p[i] = (unsigned char)(rand() & 0xff);
    return (ssize_t)buflen;
}
STUB_EOF
    EXTRA_SOURCES+=("$WORK_DIR/pdfio-getrandom-stub.c")
    ;;
*) echo "unknown TARGET_PLATFORM: $TARGET_PLATFORM" >&2; exit 1 ;;
esac

CFLAGS="$CFLAGS_BASE $CFLAGS_EXTRA -w"

#-----------------------------------------------------------------------------
# Compile the 16 pdfio sources + (optional) stubs into static archive.
#-----------------------------------------------------------------------------
PDFIO_SOURCES=(
    pdfio-aes.c
    pdfio-array.c
    pdfio-common.c
    pdfio-content.c
    pdfio-crypto.c
    pdfio-dict.c
    pdfio-file.c
    pdfio-md5.c
    pdfio-object.c
    pdfio-page.c
    pdfio-rc4.c
    pdfio-sha256.c
    pdfio-stream.c
    pdfio-string.c
    pdfio-token.c
    pdfio-value.c
)

OBJS=()
for _f in "${PDFIO_SOURCES[@]}"; do
    [ -f "$SRC_DIR/$_f" ] || { echo "missing pdfio source: $SRC_DIR/$_f" >&2; exit 1; }
    obj="$WORK_DIR/${_f%.c}.o"
    $CC $CFLAGS \
        -I"$SRC_DIR" \
        -I"$ZLIB_DIR" \
        -c "$SRC_DIR/$_f" -o "$obj"
    OBJS+=("$obj")
done

for _src in "${EXTRA_SOURCES[@]}"; do
    obj="$WORK_DIR/$(basename "${_src%.c}").o"
    $CC $CFLAGS -c "$_src" -o "$obj"
    OBJS+=("$obj")
done

$AR rcs "$INSTALL_DIR/lib/libpdfio.a" "${OBJS[@]}"

# Headers — pdfio.h is the public header; pdfio-content.h is also public
# (high-level content API). pdfio-private.h is internal but consumers
# sometimes include it. Ship all three.
cp "$SRC_DIR/pdfio.h" "$INSTALL_DIR/include/"
[ -f "$SRC_DIR/pdfio-content.h" ] && cp "$SRC_DIR/pdfio-content.h" "$INSTALL_DIR/include/"
[ -f "$SRC_DIR/pdfio-private.h" ] && cp "$SRC_DIR/pdfio-private.h" "$INSTALL_DIR/include/"

#-----------------------------------------------------------------------------
# Stage + verify
#-----------------------------------------------------------------------------
cp -a "$INSTALL_DIR/lib"     "$STAGE/"
cp -a "$INSTALL_DIR/include" "$STAGE/"

[ -f "$STAGE/lib/libpdfio.a" ] || { echo "missing libpdfio.a" >&2; exit 1; }
[ -f "$STAGE/include/pdfio.h" ] || { echo "missing pdfio.h"  >&2; exit 1; }

echo "==> packaging -> $TARBALL"
tar -C "$STAGE" -czf "$TARBALL" .

echo ""
echo "pdfio $VERSION ($TARGET_PLATFORM) ready (zlib link-deferred to consumer):"
ls -lh "$TARBALL"
tar -tzf "$TARBALL"
